1	// API test helpers — uses Node's built-in http module for maximum compatibility
2	const http = require('http');
3	const https = require('https');
4	
5	process.env.NODE_TLS_REJECT_UNAUTHORIZED = '0';
6	
7	const BASE_URL = process.env.API_BASE_URL || 'https://localhost:3443';
8	
9	function apiRequest(method, path, body = null, token = null) {
10	  return new Promise((resolve, reject) => {
11	    const url = new URL(path, BASE_URL);
12	    const isHttps = url.protocol === 'https:';
13	    const transport = isHttps ? https : http;
14	
15	    const headers = { 'Content-Type': 'application/json' };
16	    if (token) headers['Authorization'] = `Bearer ${token}`;
17	
18	    const payload = body && method !== 'GET' ? JSON.stringify(body) : null;
19	    if (payload) headers['Content-Length'] = Buffer.byteLength(payload);
20	
21	    const opts = {
22	      hostname: url.hostname,
23	      port: url.port || (isHttps ? 443 : 80),
24	      path: url.pathname + url.search,
25	      method,
26	      headers,
27	      rejectUnauthorized: false
28	    };
29	
30	    const req = transport.request(opts, (res) => {
31	      let data = '';
32	      res.on('data', chunk => data += chunk);
33	      res.on('end', () => {
34	        let json;
35	        try { json = JSON.parse(data); } catch { json = { raw: data }; }
36	        resolve({ status: res.statusCode, data: json, ok: res.statusCode >= 200 && res.statusCode < 300 });
37	      });
38	    });
39	
40	    req.on('error', reject);
41	    req.setTimeout(10000, () => { req.destroy(); reject(new Error('Request timeout')); });
42	    if (payload) req.write(payload);
43	    req.end();
44	  });
45	}
46	
47	function apiGet(path, token) { return apiRequest('GET', path, null, token); }
48	function apiPost(path, body, token) { return apiRequest('POST', path, body, token); }
49	function apiPatch(path, body, token) { return apiRequest('PATCH', path, body, token); }
50	function apiPut(path, body, token) { return apiRequest('PUT', path, body, token); }
51	function apiDelete(path, token) { return apiRequest('DELETE', path, null, token); }
52	
53	async function login(username, password) {
54	  // Use BOOTSTRAP_INITIAL_DEVICE for admin (seeded trusted device), or TEST_DEVICE for others
55	  const fp = username === 'admin' ? 'BOOTSTRAP_INITIAL_DEVICE' : 'TEST_DEVICE_' + username;
56	  const res = await apiPost('/api/auth/login', {
57	    username,
58	    password,
59	    deviceFingerprint: fp
60	  });
61	  if (res.ok && res.data?.data?.token) return res.data.data.token;
62	  if (res.ok && res.data?.token) return res.data.token;
63	  return null;
64	}
65	
66	// Cache tokens to avoid session limit issues across test suites
67	const tokenCache = {};
68	async function loginCached(username, password) {
69	  if (tokenCache[username]) {
70	    // Verify the cached token is still valid
71	    const check = await apiGet('/api/auth/me', tokenCache[username]);
72	    if (check.status === 200) return tokenCache[username];
73	    // Token expired/evicted — clear and re-login
74	    delete tokenCache[username];
75	  }
76	  const token = await login(username, password);
77	  if (token) tokenCache[username] = token;
78	  return token;
79	}
80	
81	function clearTokenCache(username) {
82	  if (username) delete tokenCache[username];
83	  else Object.keys(tokenCache).forEach(k => delete tokenCache[k]);
84	}
85	
86	module.exports = { apiGet, apiPost, apiPatch, apiPut, apiDelete, login, loginCached, clearTokenCache, BASE_URL };
87	
