9	function apiRequest(method, path, body = null, token = null) {
10	  return new Promise((resolve, reject) => {
11	    const url = new URL(path, BASE_URL);
12	    const isHttps = url.protocol === 'https:';
13	    const transport = isHttps ? https : http;
14	
15	    const headers = { 'Content-Type': 'application/json' };
16	    if (token) headers['Authorization'] = `Bearer ${token}`;
17	
18	    const payload = body && method !== 'GET' ? JSON.stringify(body) : null;
19	    if (payload) headers['Content-Length'] = Buffer.byteLength(payload);
20	
21	    const opts = {
22	      hostname: url.hostname,
23	      port: url.port || (isHttps ? 443 : 80),
24	      path: url.pathname + url.search,
25	      method,
26	      headers,
27	      rejectUnauthorized: false
28	    };
29	
30	    const req = transport.request(opts, (res) => {
31	      let data = '';
32	      res.on('data', chunk => data += chunk);
33	      res.on('end', () => {
34	        let json;
35	        try { json = JSON.parse(data); } catch { json = { raw: data }; }
36	        resolve({ status: res.statusCode, data: json, ok: res.statusCode >= 200 && res.statusCode < 300 });
37	      });
38	    });
39	
40	    req.on('error', reject);
41	    req.setTimeout(10000, () => { req.destroy(); reject(new Error('Request timeout')); });
42	    if (payload) req.write(payload);
43	    req.end();
44	  });
45	}
